import React, { useEffect, useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button, Card, Input, Table, Tag, Title, Notification } from 'animal-island-ui';
import 'animal-island-ui/style';
import { Archive, Box, CheckCircle2, ClipboardList, Download, FileSpreadsheet, Filter, Home, LogOut, Megaphone, Package, Pencil, Plus, RefreshCw, Trash2, Truck, UserPlus, Users, Wallet, X } from 'lucide-react';
import { createPortal } from 'react-dom';
import './styles.css';

type View = 'workbench' | 'projects' | 'execution' | 'archive' | 'media' | 'products' | 'import' | 'users';
type User = { id: number; email: string; name: string; role: 'Admin' | 'Editor' | 'Viewer' };
type Media = { id: number; name: string; country?: string; platform_type?: string; website_url?: string };
type ShippingAddress = { id: number; media_id: number; contact_id?: number | null; recipient_name?: string; phone?: string; email?: string; address_text: string; city?: string; region?: string; postal_code?: string; country?: string; tax_or_customs_number?: string; shipping_notes?: string; source_text?: string; is_default: boolean; is_confirmed: boolean };
type Project = { id: number; name: string; project_code?: string; owner_id?: number; status: string; budget_amount?: number; budget_currency?: string; actual_amount?: number; campaign_count?: number; owner?: User; objective?: string; notes?: string; start_date?: string; end_date?: string; is_archived?: boolean; archived_at?: string };
type Collaboration = { id: number; project_id?: number; media_id: number; owner_id?: number; collaboration_type?: string; execution_status: string; expected_publish_date?: string; next_action?: string; follow_up_date?: string; follow_up_priority?: string; follow_up_done?: boolean; notes?: string; project?: Project; media?: Media; owner?: User; shipments?: any[]; cost_items?: any[]; deliverables?: any[]; activities?: any[] };

const statusOptions = ['待确认', '待发货', '运输中', '已签收待产出', '内容审核中', '已发布', '已结算', '已暂停/取消'];
const shipmentStatusOptions = ['待发货', '运输中', '已签收待产出'];

async function api<T>(url: string, options: RequestInit = {}): Promise<T> {
  const response = await fetch(url, { credentials: 'include', headers: options.body instanceof FormData ? undefined : { 'Content-Type': 'application/json' }, ...options });
  if (!response.ok) throw new Error((await response.text()) || response.statusText);
  return response.json();
}

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<View>('workbench');
  const [loading, setLoading] = useState(true);
  useEffect(() => { api<User>('/api/auth/me').then(setUser).catch(() => setUser(null)).finally(() => setLoading(false)); }, []);
  if (loading) return <div className="splash"><img src="/assets/pangdun/pangdun_walk.gif" alt="Pangdun" /></div>;
  if (!user) return <Login onLogin={setUser} />;
  return <Shell user={user} view={view} setView={setView} onLogout={() => setUser(null)} />;
}

function Login({ onLogin }: { onLogin: (user: User) => void }) {
  const [email, setEmail] = useState('admin@example.local');
  const [password, setPassword] = useState('admin123456');
  return <main className="login-page"><section className="login-visual"><img src="/assets/pangdun/pangdun_happy.png" alt="Pangdun" /></section><form className="login-form" onSubmit={async (e) => { e.preventDefault(); try { onLogin(await api<User>('/api/auth/login', { method: 'POST', body: JSON.stringify({ email, password }) })); } catch { Notification.error({ message: '登录失败' }); } }}><Title color="app-teal" size="large">Pangdun KOL CRM</Title><label>邮箱<Input value={email} onChange={(e) => setEmail(e.target.value)} /></label><label>密码<Input type="password" value={password} onChange={(e) => setPassword(e.target.value)} /></label><Button type="primary" htmlType="submit" block>登录</Button></form></main>;
}

function Shell({ user, view, setView, onLogout }: { user: User; view: View; setView: (view: View) => void; onLogout: () => void }) {
  const nav: Array<[View, string, React.ReactNode]> = [['workbench', '执行工作台', <Home size={18} />], ['projects', '推广项目', <Megaphone size={18} />], ['execution', '合作执行单', <ClipboardList size={18} />], ['archive', '历史归档', <Archive size={18} />], ['media', '媒体 / KOL', <Users size={18} />], ['products', '产品库', <Box size={18} />], ['import', '费用表导入', <FileSpreadsheet size={18} />], ...(user.role === 'Admin' ? [['users', '用户管理', <Users size={18} />] as [View, string, React.ReactNode]] : [])];
  const logout = async () => { await api('/api/auth/logout', { method: 'POST' }); onLogout(); };
  return <div className="app-shell"><aside className="sidebar"><div className="brand"><img src="/assets/pangdun/pangdun.png" alt="Pangdun" /><div><strong>Pangdun CRM</strong><span>{user.name} · {user.role}</span></div></div><nav>{nav.map(([key, label, icon]) => <button key={key} className={view === key ? 'active' : ''} onClick={() => setView(key)}>{icon}<span>{label}</span></button>)}</nav><button className="logout" onClick={logout}><LogOut size={18} />退出</button></aside><main className="content">{view === 'workbench' && <Workbench canEdit={user.role !== 'Viewer'} />}{view === 'projects' && <Projects canEdit={user.role !== 'Viewer'} canManage={user.role === 'Admin'} />}{view === 'execution' && <Execution canEdit={user.role !== 'Viewer'} canManage={user.role === 'Admin'} />}{view === 'archive' && <ArchiveManager canManage={user.role === 'Admin'} />}{view === 'media' && <Library type="media" canEdit={user.role !== 'Viewer'} canManage={user.role === 'Admin'} />}{view === 'products' && <Library type="products" canEdit={user.role !== 'Viewer'} canManage={user.role === 'Admin'} />}{view === 'import' && <ExecutionImport />}{view === 'users' && <UsersPage />}</main></div>;
}

function PageHeader({ title, action }: { title: string; action?: React.ReactNode }) { return <header className="page-header"><div><Title color="app-teal">{title}</Title></div>{action}</header>; }
function Empty() { return <div className="empty"><img src="/assets/pangdun/pangdun_think.png" alt="" /><span>还没有记录</span></div>; }
function SelectAllHeader() { const [checked, setChecked] = useState(false); return <input type="checkbox" aria-label="全选当前列表" checked={checked} onChange={(event) => { setChecked(event.target.checked); window.dispatchEvent(new CustomEvent('workbench-select-all', { detail: event.target.checked })); }} />; }
function DataTable({ columns, data }: { columns: any[]; data: any[] }) { const normalized = columns.map((column, index) => index === 0 && column.title === '' ? { ...column, title: <SelectAllHeader /> } : column); return <div className="table-wrap"><Table columns={normalized} dataSource={data} rowKey="id" scroll={{ x: 1080 }} emptyText={<Empty />} /></div>; }
function Dialog({ title, children, onClose, onOk, okLabel = '保存', cancelLabel = '取消', footerStart }: { title: string; children: React.ReactNode; onClose: () => void; onOk?: () => void; okLabel?: string; cancelLabel?: string; footerStart?: React.ReactNode }) { return createPortal(<div className="drawer-layer" role="dialog" aria-modal="true"><section className="drawer"><header className="drawer-header"><Title color="app-teal">{title}</Title><button className="icon-button" title="关闭" onClick={onClose}><X size={19} /></button></header><div className="drawer-body">{children}</div><footer className="drawer-footer">{footerStart && <div className="drawer-footer-start">{footerStart}</div>}<div className="drawer-footer-end"><Button onClick={onClose}>{cancelLabel}</Button>{onOk && <Button type="primary" onClick={onOk}>{okLabel}</Button>}</div></footer></section></div>, document.body); }
function SelectField({ value, onChange, options, placeholder = '请选择' }: { value?: string | number; onChange: (v: string) => void; options: Array<{ key: string; label: string }>; placeholder?: string }) { return <select value={String(value ?? '')} onChange={(event) => onChange(event.target.value)}><option value="">{placeholder}</option>{options.map((option) => <option key={option.key} value={option.key}>{option.label}</option>)}</select>; }

type LookupOption = { id: number; label: string; search?: string };
function EntityLookup({ value, options, onChange, placeholder = '输入关键词搜索' }: { value?: number | null; options: LookupOption[]; onChange: (id: number | null) => void; placeholder?: string }) {
  const selected = options.find((option) => option.id === value);
  const [query, setQuery] = useState(selected?.label || '');
  const [focused, setFocused] = useState(false);
  useEffect(() => { setQuery(selected?.label || ''); }, [value, selected?.label]);
  const normalized = query.trim().toLowerCase();
  const matches = options.filter((option) => !normalized || `${option.label} ${option.search || ''}`.toLowerCase().includes(normalized)).slice(0, 8);
  return <div className="lookup-control"><div className="lookup-input-row"><input value={query} placeholder={placeholder} autoComplete="off" onFocus={() => setFocused(true)} onBlur={() => window.setTimeout(() => setFocused(false), 120)} onChange={(event) => { setQuery(event.target.value); onChange(null); }} />{value != null && <button type="button" className="lookup-clear" title="清除选择" onClick={() => { setQuery(''); onChange(null); }}>×</button>}</div>{focused && <div className="lookup-results">{matches.length ? matches.map((option) => <button type="button" key={option.id} onMouseDown={(event) => { event.preventDefault(); setQuery(option.label); onChange(option.id); setFocused(false); }}>{option.label}</button>) : <span>没有匹配结果</span>}</div>}</div>;
}

const mediaLookupOptions = (media: Media[]): LookupOption[] => media.map((item) => ({ id: item.id, label: `${item.name}${item.country ? ` · ${item.country}` : ''}${item.platform_type ? ` · ${item.platform_type}` : ''}`, search: `${item.name} ${item.country || ''} ${item.platform_type || ''} ${item.website_url || ''}` }));
const projectLookupOptions = (projects: Project[]): LookupOption[] => projects.map((item) => ({ id: item.id, label: `${item.name}${item.project_code ? ` · ${item.project_code}` : ''}`, search: `${item.name} ${item.project_code || ''} ${item.objective || ''}` }));
const campaignLookupOptions = (campaigns: Collaboration[]): LookupOption[] => campaigns.map((item) => ({ id: item.id, label: `${item.media?.name || `执行单 ${item.id}`}${item.media?.country ? ` · ${item.media.country}` : ''}`, search: `${item.media?.name || ''} ${item.media?.country || ''} ${item.project?.name || ''} ${item.execution_status || ''}` }));

function Workbench({ canEdit }: { canEdit: boolean }) {
  const [data, setData] = useState<any>({ kpis: {}, items: [] });
  const [status, setStatus] = useState(''); const [statusDraft, setStatusDraft] = useState(''); const [filterOpen, setFilterOpen] = useState(false); const [queue, setQueue] = useState('today');
  const [projects, setProjects] = useState<Project[]>([]); const [media, setMedia] = useState<Media[]>([]); const [users, setUsers] = useState<User[]>([]);
  const [selected, setSelected] = useState<Set<number>>(new Set()); const [bulk, setBulk] = useState<any>(null);
  const load = (nextStatus = status) => { const params = new URLSearchParams({ queue }); if (nextStatus) params.set('execution_status', nextStatus); return api<any>(`/api/workbench?${params}`).then((result) => { setData(result); setSelected(new Set()); }).catch(() => Notification.error({ message: '读取执行数据失败' })); };
  useEffect(() => { void load(); }, [queue]);
  useEffect(() => { api<{ items: Project[] }>('/api/projects?page_size=300').then((x) => setProjects(x.items)); api<{ items: Media[] }>('/api/media?page_size=500').then((x) => setMedia(x.items)); api<{ items: User[] }>('/api/users').then((x) => setUsers(x.items)).catch(() => {}); }, []);
  const patch = async (id: number, value: any) => { try { await api(`/api/collaborations/${id}`, { method: 'PATCH', body: JSON.stringify(value) }); await load(); } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); } };
  const applyBulk = async () => { if (!bulk || !selected.size) return; try { const payload: any = { ids: [...selected] }; if (bulk.owner_id) payload.owner_id = Number(bulk.owner_id); if (bulk.execution_status) payload.execution_status = bulk.execution_status; if (bulk.follow_up_date) payload.follow_up_date = bulk.follow_up_date; if (bulk.follow_up_priority) payload.follow_up_priority = bulk.follow_up_priority; await api('/api/collaborations/bulk', { method: 'PATCH', body: JSON.stringify(payload) }); setBulk(null); await load(); Notification.success({ message: `已更新 ${selected.size} 条执行单` }); } catch (error) { Notification.error({ message: '批量更新失败', description: String(error) }); } };
  const cards: Array<[string, number, React.ReactNode]> = [['逾期待办', data.kpis.overdue_tasks, <ClipboardList size={18} />], ['今日待办', data.kpis.today_tasks, <CheckCircle2 size={18} />], ['7 天内', data.kpis.upcoming_tasks, <Home size={18} />], ['待发货', data.kpis.pending_shipping, <Package size={18} />], ['运输中', data.kpis.in_transit, <Truck size={18} />], ['待产出', data.kpis.awaiting_content, <ClipboardList size={18} />], ['待付款', data.kpis.pending_payment, <Wallet size={18} />]];
  useEffect(() => { const selectAll = (event: Event) => { const checked = (event as CustomEvent<boolean>).detail; setSelected(checked ? new Set(data.items.map((item: any) => item.id)) : new Set()); }; window.addEventListener('workbench-select-all', selectAll); return () => window.removeEventListener('workbench-select-all', selectAll); }, [data.items]);
  const toggle = (id: number) => setSelected((previous) => { const next = new Set(previous); next.has(id) ? next.delete(id) : next.add(id); return next; });
  const openFilters = () => { setStatusDraft(status); setFilterOpen(true); };
  const applyFilters = () => { setStatus(statusDraft); setFilterOpen(false); void load(statusDraft); };
  return <section><PageHeader title="执行工作台" action={<Button icon={<RefreshCw size={16} />} onClick={() => void load()}>刷新</Button>} /><div className="queue-tabs">{[['overdue', '逾期'], ['today', '今天'], ['upcoming', '未来 7 天'], ['all', '全部执行单']].map(([key, label]) => <button key={key} className={queue === key ? 'active' : ''} onClick={() => setQueue(key)}>{label}</button>)}</div><div className="filters"><Button icon={<Filter size={16} />} onClick={openFilters}>筛选{status ? '（1）' : ''}</Button>{canEdit && selected.size > 0 && <Button type="primary" onClick={() => setBulk({})}>批量更新（{selected.size}）</Button>}</div><div className="kpi-grid">{cards.map(([label, value, icon]) => <Card key={label}><span className="metric-label">{icon}{label}</span><strong>{value || 0}</strong></Card>)}</div><section className="todo-band"><div><strong>{queue === 'overdue' ? '先清理逾期事项' : queue === 'today' ? '今天优先跟进' : '执行单列表'}</strong><span>填写下一步与跟进日期后，执行单会自动进入对应待办队列。</span></div><Tag color="app-teal">费用实付 ¥{Number(data.kpis.actual_amount || 0).toLocaleString()}</Tag></section><DataTable data={data.items} columns={[{ title: '', render: (_: any, r: any) => canEdit ? <input type="checkbox" checked={selected.has(r.id)} onChange={() => toggle(r.id)} /> : null, width: 48 }, { title: '下一步', render: (_: any, r: any) => <InlineText value={r.next_action || ''} onSave={(value) => patch(r.id, { next_action: value || null, follow_up_done: false })} />, width: 210 }, { title: '跟进日期', render: (_: any, r: any) => <InlineText type="date" value={r.follow_up_date || ''} onSave={(value) => patch(r.id, { follow_up_date: value || null, follow_up_done: false })} />, width: 135 }, { title: '优先级', render: (_: any, r: any) => <InlineSelect value={r.follow_up_priority || '普通'} options={['高', '普通', '低'].map((x) => ({ value: x, label: x }))} onSave={(value) => patch(r.id, { follow_up_priority: value })} />, width: 90 }, { title: '项目', render: (_: any, r: any) => <InlineLookup value={r.project_name} options={projects.map((x) => ({ id: x.id, label: `${x.name}${x.project_code ? ` · ${x.project_code}` : ''}` }))} onSave={(id) => patch(r.id, { project_id: id })} />, width: 190 }, { title: '合作对象', render: (_: any, r: any) => <InlineLookup value={r.media_name} options={media.map((x) => ({ id: x.id, label: `${x.name}${x.country ? ` · ${x.country}` : ''}` }))} onSave={(id) => patch(r.id, { media_id: id })} />, width: 170 }, { title: '负责人', render: (_: any, r: any) => <InlineSelect value={r.owner} options={users.map((x) => ({ value: String(x.id), label: x.name }))} onSave={(value) => patch(r.id, { owner_id: value ? Number(value) : null })} />, width: 110 }, { title: '状态', render: (_: any, r: any) => <InlineSelect value={r.execution_status} options={statusOptions.map((x) => ({ value: x, label: x }))} onSave={(value) => patch(r.id, { execution_status: value })} />, width: 145 }, { title: '物流', render: (_: any, r: any) => <InlineText value={r.tracking_number || ''} onSave={(value) => patch(r.id, { tracking_number: value || null })} />, width: 145 }, { title: '完成', render: (_: any, r: any) => canEdit && <button className="task-done" title="完成待办" onClick={() => patch(r.id, { follow_up_done: true })}><CheckCircle2 size={19} /></button>, width: 70 }]} />{filterOpen && <Dialog title="筛选执行工作台" onClose={() => setFilterOpen(false)} onOk={applyFilters} okLabel="应用筛选"><div className="form-grid"><label className="wide">执行状态<SelectField value={statusDraft} onChange={setStatusDraft} options={statusOptions.map((x) => ({ key: x, label: x }))} placeholder="全部执行状态" /></label><div className="wide"><Button onClick={() => setStatusDraft('')}>重置条件</Button></div></div></Dialog>}{bulk && <Dialog title={`批量更新 ${selected.size} 条执行单`} onClose={() => setBulk(null)} onOk={() => void applyBulk()}><div className="form-grid"><label>负责人<SelectField value={bulk.owner_id} onChange={(owner_id) => setBulk({ ...bulk, owner_id })} options={users.map((x) => ({ key: String(x.id), label: x.name }))} /></label><label>执行状态<SelectField value={bulk.execution_status} onChange={(execution_status) => setBulk({ ...bulk, execution_status })} options={statusOptions.map((x) => ({ key: x, label: x }))} /></label><label>跟进日期<Input type="date" value={bulk.follow_up_date || ''} onChange={(e) => setBulk({ ...bulk, follow_up_date: e.target.value })} /></label><label>优先级<SelectField value={bulk.follow_up_priority} onChange={(follow_up_priority) => setBulk({ ...bulk, follow_up_priority })} options={['高', '普通', '低'].map((x) => ({ key: x, label: x }))} /></label></div></Dialog>}</section>;
}

function InlineText({ value, onSave, type = 'text' }: { value: string; onSave: (value: string) => void; type?: string }) { const [editing, setEditing] = useState(false); const [draft, setDraft] = useState(value); useEffect(() => setDraft(value), [value]); if (!editing) return <button className="inline-cell" onClick={() => setEditing(true)}>{value || '—'}</button>; return <input className="inline-input" autoFocus type={type} value={draft} onChange={(e) => setDraft(e.target.value)} onBlur={() => { setEditing(false); if (draft !== value) onSave(draft); }} onKeyDown={(e) => { if (e.key === 'Escape') { setDraft(value); setEditing(false); } if (e.key === 'Enter') (e.currentTarget as HTMLInputElement).blur(); }} />; }
function InlineSelect({ value, options, onSave }: { value?: string; options: Array<{ value: string; label: string }>; onSave: (value: string) => void }) { const [editing, setEditing] = useState(false); if (!editing) return <button className="inline-cell" onClick={() => setEditing(true)}>{value || '未分配'}</button>; return <select className="inline-input" autoFocus defaultValue={options.find((x) => x.label === value)?.value || ''} onBlur={() => setEditing(false)} onChange={(e) => { setEditing(false); onSave(e.target.value); }}><option value="">未分配</option>{options.map((x) => <option key={x.value} value={x.value}>{x.label}</option>)}</select>; }
function InlineLookup({ value, options, onSave }: { value?: string; options: Array<{ id: number; label: string }>; onSave: (id: number | null) => void }) { const [editing, setEditing] = useState(false); const [draft, setDraft] = useState(value || ''); const listId = `lookup-${Math.random().toString(36).slice(2)}`; if (!editing) return <button className="inline-cell" onClick={() => { setDraft(value || ''); setEditing(true); }}>{value || '未归属'}</button>; const save = () => { const matched = options.find((x) => x.label === draft) || options.find((x) => x.label.toLowerCase().includes(draft.toLowerCase())); setEditing(false); if (matched) onSave(matched.id); else setDraft(value || ''); }; return <><input className="inline-input" autoFocus list={listId} value={draft} onChange={(e) => setDraft(e.target.value)} onBlur={save} onKeyDown={(e) => { if (e.key === 'Escape') { setDraft(value || ''); setEditing(false); } if (e.key === 'Enter') (e.currentTarget as HTMLInputElement).blur(); }} /><datalist id={listId}>{options.map((x) => <option key={x.id} value={x.label} />)}</datalist></>; }

function StatusTag({ value }: { value: string }) { return <Tag color="app-teal">{value}</Tag>; }

function Projects({ canEdit, canManage }: { canEdit: boolean; canManage: boolean }) {
  const [items, setItems] = useState<Project[]>([]); const [users, setUsers] = useState<User[]>([]); const [editing, setEditing] = useState<Partial<Project> | null>(null); const [selected, setSelected] = useState<number | null>(null);
  const load = () => api<{ items: Project[] }>('/api/projects').then((x) => setItems(x.items)); useEffect(() => { void load(); api<{ items: User[] }>('/api/users').then((x) => setUsers(x.items)).catch(() => {}); }, []);
  if (selected) return <ProjectDetail id={selected} onBack={() => { setSelected(null); load(); }} canEdit={canEdit} canManage={canManage} />;
  const save = async () => { if (!editing?.name?.trim()) return Notification.error({ message: '请填写项目名称' }); try { await api(editing.id ? `/api/projects/${editing.id}` : '/api/projects', { method: editing.id ? 'PUT' : 'POST', body: JSON.stringify({ ...editing, name: editing.name.trim() }) }); setEditing(null); await load(); Notification.success({ message: editing.id ? '项目信息已更新' : '项目已创建' }); } catch (e) { Notification.error({ message: '保存失败', description: String(e) }); } };
  const newProject = () => setEditing({ name: '', project_code: '', owner_id: undefined, objective: '', notes: '', start_date: undefined, end_date: undefined, status: 'Active', budget_currency: 'CNY', budget_amount: undefined });
  const archiveProject = async () => { if (!editing?.id || !window.confirm(`确定归档项目“${editing.name}”吗？\n\n归档后项目及其执行单会从日常列表、工作台和 KPI 中隐藏，可在“历史归档”恢复。`)) return; try { await api(`/api/projects/${editing.id}/archive`, { method: 'POST' }); setEditing(null); await load(); Notification.success({ message: '项目已归档' }); } catch (error) { Notification.error({ message: '归档失败', description: String(error) }); } };
  const deleteProject = async () => { if (!editing?.id) return; try { const detail = await api<any>(`/api/projects/${editing.id}`); const rows = detail.campaigns || []; const shipments = rows.reduce((sum: number, row: any) => sum + (row.shipments?.length || 0), 0); const costs = rows.reduce((sum: number, row: any) => sum + (row.cost_items?.length || 0), 0); const content = rows.reduce((sum: number, row: any) => sum + (row.deliverables?.length || 0), 0); const activities = rows.reduce((sum: number, row: any) => sum + (row.activities?.length || 0), 0); if (!window.confirm(`永久删除项目“${editing.name}”？\n\n将删除 ${rows.length} 条执行单、${shipments} 条寄样、${costs} 条费用、${content} 条内容和 ${activities} 条动态。媒体、联系人和产品不会删除。此操作不可撤销。`)) return; await api(`/api/projects/${editing.id}`, { method: 'DELETE' }); setEditing(null); await load(); Notification.success({ message: '项目已永久删除' }); } catch (error) { Notification.error({ message: '删除失败', description: String(error) }); } };
  return <section><PageHeader title="推广项目" action={canEdit && <Button type="primary" icon={<Plus size={16} />} onClick={newProject}>新建项目</Button>} /><DataTable data={items} columns={[{ title: '项目', render: (_: any, r: Project) => <button className="link-button" onClick={() => setSelected(r.id)}>{r.name}</button>, width: 240 }, { title: 'OA / PI', dataIndex: 'project_code', width: 180 }, { title: '负责人', render: (_: any, r: Project) => r.owner?.name || '-', width: 110 }, { title: '执行单', dataIndex: 'campaign_count', width: 90 }, { title: '预算', render: (_: any, r: Project) => r.budget_amount == null ? '-' : `${r.budget_currency || 'CNY'} ${r.budget_amount.toLocaleString()}`, width: 130 }, { title: '实付', render: (_: any, r: Project) => `¥${Number(r.actual_amount || 0).toLocaleString()}`, width: 130 }, { title: '状态', dataIndex: 'status', width: 100 }, ...(canEdit ? [{ title: '管理', render: (_: any, r: Project) => <button className="table-action" title="编辑项目信息" onClick={() => setEditing({ ...r, owner_id: r.owner_id || r.owner?.id })}><Pencil size={16} />编辑</button>, width: 105 }] : [])]} />{editing && <Dialog title={editing.id ? '编辑项目信息' : '新建推广项目'} onClose={() => setEditing(null)} onOk={() => void save()} footerStart={canManage && editing.id ? <div className="row-actions"><button className="table-action" onClick={() => void archiveProject()}><Archive size={15} />归档</button><button className="danger-button" onClick={() => void deleteProject()}><Trash2 size={15} />删除</button></div> : undefined}><ProjectForm value={editing} users={users} setValue={setEditing} /></Dialog>}</section>;
}

function ProjectForm({ value, users, setValue }: { value: Partial<Project>; users: User[]; setValue: (value: Partial<Project>) => void }) { const set = (key: keyof Project, raw: any) => setValue({ ...value, [key]: raw }); return <div className="form-grid"><label>项目名称<Input value={value.name || ''} onChange={(e) => set('name', e.target.value)} /></label><label>项目编号 / OA PI<Input value={value.project_code || ''} onChange={(e) => set('project_code', e.target.value)} /></label><label>负责人<SelectField value={value.owner_id} onChange={(ownerId) => set('owner_id', ownerId ? Number(ownerId) : undefined)} options={users.map((user) => ({ key: String(user.id), label: user.name }))} placeholder="未分配" /></label><label>项目状态<SelectField value={value.status || 'Active'} onChange={(status) => set('status', status)} options={[{ key: 'Active', label: 'Active（进行中）' }, { key: 'Completed', label: 'Completed（已完成）' }, { key: 'Paused', label: 'Paused（已暂停）' }]} /></label><label>开始日期<Input type="date" value={value.start_date || ''} onChange={(e) => set('start_date', e.target.value || null)} /></label><label>结束日期<Input type="date" value={value.end_date || ''} onChange={(e) => set('end_date', e.target.value || null)} /></label><label>预算金额<Input type="number" value={value.budget_amount ?? ''} onChange={(e) => set('budget_amount', e.target.value ? Number(e.target.value) : null)} /></label><label>币种<Input value={value.budget_currency || 'CNY'} onChange={(e) => set('budget_currency', e.target.value)} /></label><label className="wide">项目目标<textarea value={value.objective || ''} onChange={(e) => set('objective', e.target.value)} /></label><label className="wide">项目备注<textarea value={value.notes || ''} onChange={(e) => set('notes', e.target.value)} /></label></div>; }

function ProjectDetail({ id, onBack, canEdit, canManage }: { id: number; onBack: () => void; canEdit: boolean; canManage: boolean }) {
  const [data, setData] = useState<any>(null); const [loading, setLoading] = useState(true); const [loadError, setLoadError] = useState(''); const [kind, setKind] = useState<'shipment' | 'cost' | 'content' | 'activity' | null>(null); const [editing, setEditing] = useState<Partial<Project> | null>(null); const [editingCollaboration, setEditingCollaboration] = useState<Collaboration | null>(null); const [users, setUsers] = useState<User[]>([]);
  const load = async () => { setLoading(true); setLoadError(''); try { setData(await api<any>(`/api/projects/${id}`)); } catch (error) { setData(null); setLoadError(String(error)); } finally { setLoading(false); } };
  useEffect(() => { void load(); api<{ items: User[] }>('/api/users').then((x) => setUsers(x.items)).catch(() => {}); }, [id]);
  if (loading) return <section><PageHeader title="加载项目" action={<Button onClick={onBack}>返回项目</Button>} /><div className="loading-state">正在读取项目详情...</div></section>;
  if (loadError) return <section><PageHeader title="项目详情" action={<Button onClick={onBack}>返回项目</Button>} /><div className="error-state"><strong>读取项目详情失败</strong><span>请刷新重试；若问题持续出现，请保留当前项目名称和报错信息。</span><div><Button onClick={() => void load()}>重新加载</Button><Button onClick={onBack}>返回项目列表</Button></div></div></section>;
  if (!data) return <section><PageHeader title="项目详情" action={<Button onClick={onBack}>返回项目</Button>} /><Empty /></section>;
  const project: Project = data.project; const collaborations: Collaboration[] = data.campaigns || []; const summary = data.summary || {};
  const saveProject = async () => { if (!editing?.name?.trim()) return Notification.error({ message: '请填写项目名称' }); try { await api(`/api/projects/${id}`, { method: 'PUT', body: JSON.stringify({ ...editing, name: editing.name.trim() }) }); setEditing(null); await load(); Notification.success({ message: '项目信息已更新' }); } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); } };
  const archiveProject = async () => { if (!window.confirm(`确定归档项目“${project.name}”吗？\n\n归档后项目及其执行单会从日常列表、工作台和 KPI 中隐藏，可在“历史归档”恢复。`)) return; try { await api(`/api/projects/${id}/archive`, { method: 'POST' }); Notification.success({ message: '项目已归档' }); onBack(); } catch (error) { Notification.error({ message: '归档失败', description: String(error) }); } };
  const deleteProject = async () => { const rows = collaborations; const shipments = rows.reduce((sum, row) => sum + (row.shipments?.length || 0), 0); const costs = rows.reduce((sum, row) => sum + (row.cost_items?.length || 0), 0); const content = rows.reduce((sum, row) => sum + (row.deliverables?.length || 0), 0); const activities = rows.reduce((sum, row) => sum + (row.activities?.length || 0), 0); if (!window.confirm(`永久删除项目“${project.name}”？\n\n将删除 ${rows.length} 条执行单、${shipments} 条寄样、${costs} 条费用、${content} 条内容和 ${activities} 条动态。媒体、联系人和产品不会删除。此操作不可撤销。`)) return; try { await api(`/api/projects/${id}`, { method: 'DELETE' }); Notification.success({ message: '项目已永久删除' }); onBack(); } catch (error) { Notification.error({ message: '删除失败', description: String(error) }); } };
  return <section><PageHeader title={project.name} action={<div className="page-actions">{canEdit && <Button icon={<Pencil size={16} />} onClick={() => setEditing({ ...project, owner_id: project.owner_id || project.owner?.id })}>编辑项目信息</Button>}<a className="export-link" href={`/api/projects/${id}/report.xlsx`}><Download size={16} />导出复盘</a><Button onClick={onBack}>返回项目</Button></div>} /><div className="project-hero"><div><span>项目编号 {project.project_code || '未填写'} · 负责人 {project.owner?.name || '未分配'}</span><h2>{project.objective || '尚未填写项目目标'}</h2></div><div className="project-totals"><span>预算 ¥{Number(project.budget_amount || 0).toLocaleString()}</span><strong>实付 ¥{Number(data.actual_amount || 0).toLocaleString()}</strong><span>差额 ¥{Number((project.budget_amount || 0) - (data.actual_amount || 0)).toLocaleString()}</span></div></div><section className="result-summary"><div><span>合作对象</span><strong>{summary.collaboration_count || 0}</strong></div><div><span>已发布 / 完成率</span><strong>{summary.published_count || 0} · {summary.completion_rate || 0}%</strong></div><div><span>总曝光</span><strong>{Number(summary.impressions || 0).toLocaleString()}</strong></div><div><span>总互动</span><strong>{Number((summary.likes || 0) + (summary.comments || 0)).toLocaleString()}</strong></div><div><span>CPM</span><strong>{summary.cpm == null ? '待补充数据' : `¥${Number(summary.cpm).toLocaleString()}`}</strong><small>{summary.cpm_base ? `按${summary.cpm_base}计算` : '需填写曝光或播放'}</small></div></section><div className="detail-actions">{canEdit && <><Button icon={<Truck size={16} />} onClick={() => setKind('shipment')}>登记寄样</Button><Button icon={<Wallet size={16} />} onClick={() => setKind('cost')}>登记费用</Button><Button icon={<ClipboardList size={16} />} onClick={() => setKind('content')}>登记内容</Button><Button onClick={() => setKind('activity')}>记录动态</Button></>}</div><DataTable data={collaborations} columns={[{ title: '合作对象', render: (_: any, r: Collaboration) => r.media?.name || r.media_id, width: 180 }, { title: '下一步', dataIndex: 'next_action', width: 180 }, { title: '跟进日期', dataIndex: 'follow_up_date', width: 120 }, { title: '负责人', render: (_: any, r: Collaboration) => r.owner?.name || '-', width: 100 }, { title: '执行状态', render: (_: any, r: Collaboration) => <StatusTag value={r.execution_status} />, width: 140 }, { title: '内容', render: (_: any, r: Collaboration) => r.deliverables?.[0]?.url ? <a href={r.deliverables[0].url} target="_blank">查看产出</a> : '未登记', width: 110 }, { title: '费用', render: (_: any, r: Collaboration) => `¥${(r.cost_items || []).reduce((sum: number, x: any) => sum + Number(x.actual_amount || 0), 0).toLocaleString()}`, width: 120 }, ...(canEdit ? [{ title: '管理', render: (_: any, r: Collaboration) => <button className="table-action" onClick={() => setEditingCollaboration(r)}><Pencil size={15} />编辑</button>, width: 100 }] : [])]} />{kind && <AddRecord projectId={id} kind={kind} campaigns={collaborations} onClose={() => setKind(null)} onSaved={() => { setKind(null); load(); }} />}{editing && <Dialog title="编辑项目信息" onClose={() => setEditing(null)} onOk={() => void saveProject()}><ProjectForm value={editing} users={users} setValue={setEditing} /></Dialog>}{editingCollaboration && <CollaborationEditor value={editingCollaboration} onClose={() => setEditingCollaboration(null)} onSaved={() => { setEditingCollaboration(null); load(); }} />}</section>;
}

function LegacyAddRecord({ projectId, kind, campaigns, onClose, onSaved }: { projectId: number; kind: 'shipment' | 'cost' | 'content' | 'activity'; campaigns: Collaboration[]; onClose: () => void; onSaved: () => void }) {
  const [campaignId, setCampaignId] = useState<number | null>(campaigns[0]?.id || null);
  const [media, setMedia] = useState<Media[]>([]);
  const [products, setProducts] = useState<any[]>([]);
  const [addresses, setAddresses] = useState<ShippingAddress[]>([]);
  const [mediaId, setMediaId] = useState<number | null>(campaigns[0]?.media_id || null);
  const [shipmentSource, setShipmentSource] = useState<'project' | 'library'>('project');
  const [productId, setProductId] = useState<number | null>(null);
  const [form, setForm] = useState<any>({ status: '待发货', cost_type: '评测费用', payment_status: '未付款', deliverable_type: 'Other', activity_type: '备注' });
  const set = (key: string, value: any) => setForm((current: any) => ({ ...current, [key]: value }));

  useEffect(() => {
    if (kind !== 'shipment') return;
    api<{ items: Media[] }>('/api/media?page_size=500').then((result) => setMedia(result.items));
    api<{ items: any[] }>('/api/products?page_size=500').then((result) => setProducts(result.items));
  }, [kind]);
  useEffect(() => {
    if (kind !== 'shipment' || !mediaId) { setAddresses([]); return; }
    api<ShippingAddress[]>(`/api/media/${mediaId}/shipping-addresses`).then((rows) => {
      setAddresses(rows);
      const selected = rows.find((row) => row.is_default) || rows[0];
      setForm((current: any) => ({ ...current, shipping_address_id: selected?.id || null, recipient_address: selected ? formatAddress(selected) : '' }));
    });
  }, [kind, mediaId]);

  const selectCampaign = (id: number | null) => {
    setCampaignId(id);
    const campaign = campaigns.find((item) => item.id === id);
    if (campaign) { setMediaId(campaign.media_id); setShipmentSource('project'); } else setMediaId(null);
  };
  const chooseLibrary = () => {
    setShipmentSource('library'); setCampaignId(null); setMediaId(null);
    setForm((current: any) => ({ ...current, shipping_address_id: null, recipient_address: '' }));
  };
  const chooseAddress = (value: string) => {
    const selected = addresses.find((row) => row.id === Number(value));
    setForm((current: any) => ({ ...current, shipping_address_id: selected?.id || null, recipient_address: selected ? formatAddress(selected) : '' }));
  };
  const save = async () => {
    try {
      if (kind !== 'shipment' && !campaignId) return Notification.error({ message: '请选择合作对象' });
      const base = { ...form, campaign_id: campaignId };
      if (kind === 'shipment') {
        const product = products.find((item) => item.id === productId);
        if (!mediaId) return Notification.error({ message: shipmentSource === 'project' ? '请从本项目合作对象中选择执行单' : '请从 KOL 媒体库选择合作对象' });
        await api(`/api/projects/${projectId}/shipments`, { method: 'POST', body: JSON.stringify({ ...form, media_id: mediaId, campaign_id: shipmentSource === 'project' ? campaignId : null, items: product ? [{ product_id: product.id, product_name: product.model, quantity: 1 }] : form.product_name ? [{ product_name: form.product_name, quantity: 1 }] : [] }) });
      }
      if (kind === 'cost') await api('/api/cost-items', { method: 'POST', body: JSON.stringify({ ...base, actual_amount: form.actual_amount ? Number(form.actual_amount) : null, planned_amount: form.planned_amount ? Number(form.planned_amount) : null }) });
      if (kind === 'content') await api('/api/deliverables', { method: 'POST', body: JSON.stringify(base) });
      if (kind === 'activity') await api('/api/activities', { method: 'POST', body: JSON.stringify(base) });
      onSaved();
    } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); }
  };

  const shipmentOptions: LookupOption[] = campaigns.map((item) => ({ id: item.id, label: `${item.media?.name || `执行单 ${item.id}`} · ${item.execution_status}${item.owner?.name ? ` · ${item.owner.name}` : ''}`, search: `${item.media?.name || ''} ${item.media?.country || ''} ${item.execution_status} ${item.owner?.name || ''}` }));
  return <Dialog title={{ shipment: '登记寄样', cost: '登记费用', content: '登记内容产出', activity: '记录动态' }[kind]} onClose={onClose} onOk={save}>
    <div className="form-grid">
      {kind !== 'shipment' && <label className="wide">合作对象<EntityLookup value={campaignId} onChange={setCampaignId} options={campaignLookupOptions(campaigns)} placeholder="输入 KOL、国家、项目或状态" /></label>}
      {kind === 'shipment' && <>
        <label className="wide">本项目合作对象<EntityLookup value={shipmentSource === 'project' ? campaignId : null} onChange={selectCampaign} options={shipmentOptions} placeholder={campaigns.length ? '输入 KOL、状态或负责人匹配执行单' : '本项目尚未创建合作执行单'} /></label>
        <div className="wide shipment-source-note"><span>{shipmentSource === 'project' && campaignId ? '寄样将精确关联到选中的合作执行单。' : '没有对应执行单时，可从媒体库新增合作对象。'}</span><button type="button" className="link-button" onClick={chooseLibrary}>从媒体 / KOL 库另选</button></div>
        {shipmentSource === 'library' && <label className="wide">从媒体 / KOL 库选择<EntityLookup value={mediaId} onChange={setMediaId} options={mediaLookupOptions(media)} placeholder="输入名称、国家、渠道或主页链接" /></label>}
        {mediaId && <>
          <label className="wide">收件地址<SelectField value={form.shipping_address_id || ''} onChange={chooseAddress} options={addresses.map((row) => ({ key: String(row.id), label: `${row.is_default ? '默认 · ' : ''}${row.recipient_name || '未填写收件人'} · ${row.address_text}` }))} placeholder={addresses.length ? '选择地址档案' : '该媒体尚未登记地址'} /></label>
          <label className="wide">本次寄样收件信息<textarea value={form.recipient_address || ''} onChange={(event) => set('recipient_address', event.target.value)} placeholder="选择地址后可继续修改，本次保存为快照" /></label>
        </>}
        <label>OA / PI<Input value={form.oa_pi_number || ''} onChange={(event) => set('oa_pi_number', event.target.value)} /></label>
        <label>物流单号<Input value={form.tracking_number || ''} onChange={(event) => set('tracking_number', event.target.value)} /></label>
        <label>承运商<Input value={form.carrier || ''} onChange={(event) => set('carrier', event.target.value)} /></label>
        <label>物流状态<SelectField value={form.status} onChange={(value) => set('status', value)} options={shipmentStatusOptions.map((value) => ({ key: value, label: value }))} /></label>
        <label className="wide">产品库<EntityLookup value={productId} onChange={setProductId} options={products.map((item) => ({ id: item.id, label: item.model, search: `${item.model} ${item.full_name || ''} ${item.aliases || ''} ${item.platform || ''}` }))} placeholder="输入完整型号、别名或芯片组" /></label>
        <label className="wide">或输入新产品名称<Input value={form.product_name || ''} onChange={(event) => set('product_name', event.target.value)} /></label>
      </>}
      {kind === 'cost' && <>
        <label>费用类型<SelectField value={form.cost_type} onChange={(value) => set('cost_type', value)} options={['产品费用', '物流/关税', '评测费用', '其他费用'].map((value) => ({ key: value, label: value }))} /></label>
        <label>付款状态<SelectField value={form.payment_status} onChange={(value) => set('payment_status', value)} options={['未付款', '部分付款', '已付款', '无需付款'].map((value) => ({ key: value, label: value }))} /></label>
        <label>预算金额<Input value={form.planned_amount || ''} onChange={(event) => set('planned_amount', event.target.value)} /></label>
        <label>实付金额<Input value={form.actual_amount || ''} onChange={(event) => set('actual_amount', event.target.value)} /></label>
      </>}
      {kind === 'content' && <>
        <label>内容类型<Input value={form.deliverable_type || 'Other'} onChange={(event) => set('deliverable_type', event.target.value)} /></label>
        <label>内容链接<Input value={form.url || ''} onChange={(event) => set('url', event.target.value)} /></label>
        <label>播放 / 阅读<Input value={form.views || ''} onChange={(event) => set('views', event.target.value ? Number(event.target.value) : null)} /></label>
      </>}
      {kind === 'activity' && <label className="wide">内容<textarea value={form.content || ''} onChange={(event) => set('content', event.target.value)} /></label>}
    </div>
  </Dialog>;
}

function AddRecord({ projectId, kind, campaigns, onClose, onSaved }: { projectId: number; kind: 'shipment' | 'cost' | 'content' | 'activity'; campaigns: Collaboration[]; onClose: () => void; onSaved: () => void }) {
  const [campaignId, setCampaignId] = useState<number | null>(campaigns[0]?.id || null);
  const [form, setForm] = useState<any>({ deliverable_type: 'Other', url: '', published_at: '', impressions: null, views: null, likes: null, comments: null });
  if (kind !== 'content') return <LegacyAddRecord projectId={projectId} kind={kind} campaigns={campaigns} onClose={onClose} onSaved={onSaved} />;
  const set = (key: string, value: any) => setForm({ ...form, [key]: value });
  const save = async () => { if (!campaignId) return Notification.error({ message: '请选择合作对象' }); try { await api('/api/deliverables', { method: 'POST', body: JSON.stringify({ ...form, campaign_id: campaignId }) }); onSaved(); } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); } };
  return <Dialog title="登记内容产出" onClose={onClose} onOk={() => void save()}><div className="form-grid"><label className="wide">合作对象<EntityLookup value={campaignId} onChange={setCampaignId} options={campaignLookupOptions(campaigns)} placeholder="输入 KOL、国家、项目或状态" /></label><label>内容类型<Input value={form.deliverable_type} onChange={(e) => set('deliverable_type', e.target.value)} /></label><label>发布时间<Input type="date" value={form.published_at} onChange={(e) => set('published_at', e.target.value || null)} /></label><label className="wide">内容链接<Input value={form.url} onChange={(e) => set('url', e.target.value)} /></label><label>曝光量<Input value={form.impressions || ''} onChange={(e) => set('impressions', e.target.value ? Number(e.target.value) : null)} /></label><label>播放 / 阅读<Input value={form.views || ''} onChange={(e) => set('views', e.target.value ? Number(e.target.value) : null)} /></label><label>点赞<Input value={form.likes || ''} onChange={(e) => set('likes', e.target.value ? Number(e.target.value) : null)} /></label><label>评论<Input value={form.comments || ''} onChange={(e) => set('comments', e.target.value ? Number(e.target.value) : null)} /></label></div></Dialog>;
}

function CollaborationEditor({ value, onClose, onSaved, canManage = false }: { value: Collaboration; onClose: () => void; onSaved: () => void; canManage?: boolean }) {
  const [form, setForm] = useState<any>({ ...value, project_id: value.project_id, media_id: value.media_id, owner_id: value.owner_id, expected_publish_date: value.expected_publish_date || '', notes: value.notes || '', collaboration_type: value.collaboration_type || '' });
  const [projects, setProjects] = useState<Project[]>([]); const [media, setMedia] = useState<Media[]>([]); const [users, setUsers] = useState<User[]>([]);
  useEffect(() => { api<{ items: Project[] }>('/api/projects?page_size=300').then((x) => setProjects(x.items)); api<{ items: Media[] }>('/api/media?page_size=500').then((x) => setMedia(x.items)); api<{ items: User[] }>('/api/users').then((x) => setUsers(x.items)).catch(() => {}); }, []);
  const save = async () => { if (!form.media_id) return Notification.error({ message: '请选择合作对象' }); try { await api(`/api/collaborations/${value.id}`, { method: 'PATCH', body: JSON.stringify({ project_id: form.project_id || null, media_id: form.media_id, owner_id: form.owner_id || null, collaboration_type: form.collaboration_type || null, execution_status: form.execution_status, expected_publish_date: form.expected_publish_date || null, notes: form.notes || null }) }); Notification.success({ message: '执行单已更新' }); onSaved(); } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); } };
  const archive = async () => { if (!window.confirm(`确定归档合作执行单“${value.media?.name || value.id}”吗？\n\n归档后将从日常列表和工作台隐藏，可在“历史归档”恢复。`)) return; try { await api(`/api/campaigns/${value.id}/archive`, { method: 'POST' }); Notification.success({ message: '执行单已归档' }); onSaved(); } catch (error) { Notification.error({ message: '归档失败', description: String(error) }); } };
  const remove = async () => { try { const detail = await api<any>(`/api/collaborations/${value.id}`); if (!window.confirm(`永久删除合作执行单“${value.media?.name || value.id}”？\n\n将删除 ${detail.shipments?.length || 0} 条寄样、${detail.cost_items?.length || 0} 条费用、${detail.deliverables?.length || 0} 条内容和 ${detail.activities?.length || 0} 条动态。媒体、联系人和产品不会删除。此操作不可撤销。`)) return; await api(`/api/campaigns/${value.id}`, { method: 'DELETE' }); Notification.success({ message: '执行单已永久删除' }); onSaved(); } catch (error) { Notification.error({ message: '删除失败', description: String(error) }); } };
  return <Dialog title={`编辑合作执行单 · ${value.media?.name || ''}`} onClose={onClose} onOk={() => void save()} footerStart={canManage ? <div className="row-actions"><button className="table-action" onClick={() => void archive()}><Archive size={15} />归档</button><button className="danger-button" onClick={() => void remove()}><Trash2 size={15} />删除</button></div> : undefined}><div className="form-grid"><label>推广项目<EntityLookup value={form.project_id} onChange={(projectId) => setForm({ ...form, project_id: projectId })} options={projectLookupOptions(projects)} placeholder="输入项目名称、OA/PI 或目标" /></label><label>合作对象<EntityLookup value={form.media_id} onChange={(mediaId) => setForm({ ...form, media_id: mediaId })} options={mediaLookupOptions(media)} placeholder="输入名称、国家、渠道或主页链接" /></label><label>负责人<SelectField value={form.owner_id} onChange={(ownerId) => setForm({ ...form, owner_id: ownerId ? Number(ownerId) : null })} options={users.map((user) => ({ key: String(user.id), label: user.name }))} placeholder="未分配" /></label><label>执行状态<SelectField value={form.execution_status} onChange={(execution_status) => setForm({ ...form, execution_status })} options={statusOptions.map((status) => ({ key: status, label: status }))} /></label><label>推广形式<Input value={form.collaboration_type} onChange={(event) => setForm({ ...form, collaboration_type: event.target.value })} /></label><label>预计产出<Input type="date" value={form.expected_publish_date} onChange={(event) => setForm({ ...form, expected_publish_date: event.target.value })} /></label><label className="wide">合作备注<textarea value={form.notes} onChange={(event) => setForm({ ...form, notes: event.target.value })} /></label></div></Dialog>;
}

