function ArchiveManager({ canManage }: { canManage: boolean }) {
  const [projects, setProjects] = useState<any[]>([]); const [campaigns, setCampaigns] = useState<any[]>([]); const [detail, setDetail] = useState<any>(null);
  const load = () => { api<{ items: any[] }>('/api/projects?history_only=true&page_size=300').then((x) => setProjects(x.items)); api<{ items: any[] }>('/api/campaigns?history_only=true&page_size=500').then((x) => setCampaigns(x.items)); };
  useEffect(() => { void load(); }, []);
  const run = async (url: string, success: string) => { try { await api(url, { method: 'POST' }); await load(); Notification.success({ message: success }); } catch (error) { Notification.error({ message: '操作失败', description: String(error) }); } };
  const remove = async (url: string, message: string) => { if (!window.confirm(message)) return; try { await api(url, { method: 'DELETE' }); setDetail(null); await load(); Notification.success({ message: '已永久删除' }); } catch (error) { Notification.error({ message: '删除失败', description: String(error) }); } };
  return <section><PageHeader title="历史归档" action={<Button icon={<RefreshCw size={16} />} onClick={() => void load()}>刷新</Button>} /><section className="todo-band"><div><strong>手动归档与历史导入记录</strong><span>手动归档可恢复；删除会永久清除关联执行数据，无法撤销。</span></div><Tag color="app-teal">项目 {projects.length} · 执行单 {campaigns.length}</Tag></section><h3 className="section-title">归档项目</h3><DataTable data={projects} columns={[{ title: '项目', dataIndex: 'name', width: 280 }, { title: '来源', render: (_: any, row: any) => row.is_archived ? '手动归档' : '历史导入', width: 120 }, { title: '执行单', dataIndex: 'campaign_count', width: 100 }, { title: '操作', render: (_: any, row: any) => canManage ? <div className="row-actions">{row.is_archived && <button className="table-action" onClick={() => void run(`/api/projects/${row.id}/restore`, '项目已恢复')}>恢复</button>}<button className="danger-button" onClick={() => void remove(`/api/projects/${row.id}`, `永久删除项目“${row.name}”及其 ${row.campaign_count || 0} 条执行单？此操作不可撤销。`)}><Trash2 size={15} />删除</button></div> : '仅管理员可管理', width: 190 }]} /><h3 className="section-title">归档合作执行单</h3><DataTable data={campaigns} columns={[{ title: '项目', render: (_: any, row: any) => row.project?.name || '历史导入', width: 240 }, { title: 'KOL / 媒体', render: (_: any, row: any) => row.media?.name || '-', width: 190 }, { title: '来源', render: (_: any, row: any) => row.archived_at ? '手动归档' : '历史导入', width: 120 }, { title: '状态', render: (_: any, row: any) => <StatusTag value={row.execution_status} />, width: 140 }, { title: '操作', render: (_: any, row: any) => <div className="row-actions"><Button onClick={async () => { try { setDetail(await api<any>(`/api/collaborations/${row.id}`)); } catch { Notification.error({ message: '读取执行单详情失败' }); } }}>查看</Button>{canManage && <>{row.archived_at && <button className="table-action" onClick={() => void run(`/api/campaigns/${row.id}/restore`, '执行单已恢复')}>恢复</button>}<button className="danger-button" onClick={() => void remove(`/api/campaigns/${row.id}`, `永久删除合作执行单“${row.media?.name || row.id}”？此操作不可撤销。`)}><Trash2 size={15} />删除</button></>}</div>, width: 240 }]} />{detail && <Dialog title={`执行单详情 · ${detail.media?.name || ''}`} onClose={() => setDetail(null)}><div className="history-detail"><div><span>项目</span><strong>{detail.project?.name || '-'}</strong></div><div><span>状态</span><strong>{detail.execution_status}</strong></div><div><span>寄样</span><strong>{detail.shipments?.map((item: any) => item.tracking_number || item.oa_pi_number || item.status).join('；') || '未登记'}</strong></div><div><span>费用</span><strong>{detail.cost_items?.map((item: any) => `${item.cost_type} ¥${item.actual_amount || 0}`).join('；') || '未登记'}</strong></div></div></Dialog>}</section>;
}

function Library({ type, canEdit, canManage }: { type: 'media' | 'products' | 'contacts'; canEdit: boolean; canManage: boolean }) { if (type === 'media') return <MediaManager canEdit={canEdit} />; if (type === 'contacts') return <ContactManager canEdit={canEdit} />; return <ProductManager canEdit={canEdit} canManage={canManage} />; }

function MediaManager({ canEdit }: { canEdit: boolean }) {
  const [items, setItems] = useState<any[]>([]); const [allMedia, setAllMedia] = useState<any[]>([]); const [q, setQ] = useState(''); const [filters, setFilters] = useState({ country: '', platform_type: '', media_tier: '', cooperation_status: '' }); const [filterDraft, setFilterDraft] = useState(filters); const [filterOpen, setFilterOpen] = useState(false); const [editing, setEditing] = useState<any>(null); const [detailId, setDetailId] = useState<number | null>(null); const [importOpen, setImportOpen] = useState(false);
  const load = (nextFilters = filters, nextQuery = q) => { const params = new URLSearchParams({ q: nextQuery, page_size: '500' }); Object.entries(nextFilters).forEach(([key, value]) => { if (value) params.set(key, value); }); return api<{ items: any[] }>(`/api/media?${params}`).then((x) => setItems(x.items)); };
  useEffect(() => { void load(); api<{ items: any[] }>('/api/media?page_size=500').then((x) => setAllMedia(x.items)); }, []);
  const options = (key: string) => [...new Set(allMedia.map((item) => item[key]).filter(Boolean))].sort();
  const save = async () => { const existing = await api<any>(`/api/media-duplicates?name=${encodeURIComponent(editing.name || '')}&website_url=${encodeURIComponent(editing.website_url || '')}&country=${encodeURIComponent(editing.country || '')}`); if (!editing.id && existing.items.length && !window.confirm(`发现 ${existing.items.length} 个相同媒体候选，仍要新建吗？`)) return; await api(editing.id ? `/api/media/${editing.id}` : '/api/media', { method: editing.id ? 'PUT' : 'POST', body: JSON.stringify(editing) }); setEditing(null); await load(); api<{ items: any[] }>('/api/media?page_size=500').then((x) => setAllMedia(x.items)); };
  const updateDraft = (key: keyof typeof filters, value: string) => setFilterDraft({ ...filterDraft, [key]: value });
  const appliedCount = Object.values(filters).filter(Boolean).length;
  const openFilters = () => { setFilterDraft(filters); setFilterOpen(true); };
  const applyFilters = () => { setFilters(filterDraft); setFilterOpen(false); void load(filterDraft); };
  return <section><PageHeader title="媒体 / KOL 档案" action={<div className="page-actions">{canEdit && <><Button icon={<FileSpreadsheet size={16} />} onClick={() => setImportOpen(true)}>地址导入审核</Button><Button type="primary" icon={<Plus size={16} />} onClick={() => setEditing({ name: '', country: '', platform_type: '', website_url: '', category: '', notes: '' })}>新建媒体</Button></>}<Button icon={<RefreshCw size={16} />} onClick={() => void load()}>刷新</Button></div>} /><div className="filters media-toolbar"><Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="搜索媒体、联系人、链接或备注" /><Button onClick={() => void load()}>查询</Button><Button icon={<Filter size={16} />} onClick={openFilters}>筛选{appliedCount ? `（${appliedCount}）` : ''}</Button></div><DataTable data={items} columns={[{ title: '名称', render: (_: any, r: any) => <button className="link-button" onClick={() => setDetailId(r.id)}>{r.name}</button>, width: 230 }, { title: '国家', dataIndex: 'country', width: 110 }, { title: '渠道', dataIndex: 'platform_type', width: 130 }, { title: '等级', dataIndex: 'media_tier', width: 90 }, { title: '主页', render: (_: any, r: Media) => r.website_url ? <a href={r.website_url} target="_blank">打开主页</a> : '-' }, { title: '档案', render: (_: any, r: any) => <button className="table-action" onClick={() => setDetailId(r.id)}>查看联系人与地址</button>, width: 180 }, ...(canEdit ? [{ title: '操作', render: (_: any, r: any) => <button className="table-action" onClick={() => setEditing({ ...r })}><Pencil size={15} />编辑</button>, width: 90 }] : [])]} />{filterOpen && <Dialog title="筛选媒体 / KOL" onClose={() => setFilterOpen(false)} onOk={applyFilters} okLabel="应用筛选"><div className="form-grid"><label>国家<SelectField value={filterDraft.country} onChange={(value) => updateDraft('country', value)} options={options('country').map((value) => ({ key: value, label: value }))} placeholder="全部国家" /></label><label>渠道<SelectField value={filterDraft.platform_type} onChange={(value) => updateDraft('platform_type', value)} options={options('platform_type').map((value) => ({ key: value, label: value }))} placeholder="全部渠道" /></label><label>媒体等级<SelectField value={filterDraft.media_tier} onChange={(value) => updateDraft('media_tier', value)} options={options('media_tier').map((value) => ({ key: value, label: value }))} placeholder="全部等级" /></label><label>合作状态<SelectField value={filterDraft.cooperation_status} onChange={(value) => updateDraft('cooperation_status', value)} options={options('cooperation_status').map((value) => ({ key: value, label: value }))} placeholder="全部合作状态" /></label><div className="wide"><Button onClick={() => setFilterDraft({ country: '', platform_type: '', media_tier: '', cooperation_status: '' })}>重置条件</Button></div></div></Dialog>}{editing && <Dialog title={editing.id ? '编辑媒体' : '新建媒体'} onClose={() => setEditing(null)} onOk={() => void save()}><MediaForm value={editing} setValue={setEditing} /></Dialog>}{detailId && <MediaDetailDrawer mediaId={detailId} canEdit={canEdit} onClose={() => setDetailId(null)} onChanged={() => void load()} />}{importOpen && <AddressImportReview onClose={() => setImportOpen(false)} />}</section>;
}

function MediaDetailDrawer({ mediaId, canEdit, onClose, onChanged }: { mediaId: number; canEdit: boolean; onClose: () => void; onChanged: () => void }) {
  const [data, setData] = useState<any>(null); const [contact, setContact] = useState<any>(null); const [address, setAddress] = useState<any>(null);
  const load = () => api<any>(`/api/media/${mediaId}`).then(setData).catch((error) => Notification.error({ message: '读取媒体档案失败', description: String(error) })); useEffect(() => { void load(); }, [mediaId]);
  const removeContact = async (item: any) => { if (!window.confirm(`删除联系人“${item.name || '未命名'}”？关联地址会保留在媒体档案中。`)) return; await api(`/api/contacts/${item.id}`, { method: 'DELETE' }); await load(); };
  const removeAddress = async (item: ShippingAddress) => { if (!window.confirm('删除这条地址档案？历史寄样快照不会受影响。')) return; await api(`/api/shipping-addresses/${item.id}`, { method: 'DELETE' }); await load(); };
  const makeDefault = async (item: ShippingAddress) => { await api(`/api/shipping-addresses/${item.id}/default`, { method: 'POST' }); await load(); };
  if (!data) return <Dialog title="媒体档案" onClose={onClose}><div className="loading-state">正在读取档案...</div></Dialog>;
  const media = data.media; const contacts = data.contacts || []; const addresses: ShippingAddress[] = data.shipping_addresses || [];
  return <Dialog title={media.name} onClose={onClose}><div className="media-detail"><div className="record-summary"><strong>{media.country || '未填写国家'} · {media.platform_type || '未填写渠道'}</strong>{media.website_url && <a href={media.website_url} target="_blank">打开主页</a>}<span>{media.notes || '暂无媒体备注'}</span></div><div className="section-heading"><h3>联系人</h3>{canEdit && <Button icon={<UserPlus size={15} />} onClick={() => setContact({ media_id: media.id, name: '', role: '', email: '', phone: '' })}>新增联系人</Button>}</div>{contacts.length ? <div className="record-list">{contacts.map((item: any) => <div className="record-row" key={item.id}><div><strong>{item.name || '未命名'}{item.is_primary ? ' · 主联系人' : ''}</strong><span>{[item.role, item.email, item.phone].filter(Boolean).join(' · ') || '暂无联系方式'}</span></div>{canEdit && <div className="row-actions"><button className="table-action" onClick={() => setContact(item)}><Pencil size={14} />编辑</button><button className="table-action danger-text" onClick={() => void removeContact(item)}><Trash2 size={14} />删除</button></div>}</div>)}</div> : <p className="muted">尚未登记联系人</p>}<div className="section-heading"><h3>收件地址</h3>{canEdit && <Button icon={<Plus size={15} />} onClick={() => setAddress({ media_id: media.id, contact_id: null, address_text: '', country: media.country || '', is_default: !addresses.length, is_confirmed: true })}>新增地址</Button>}</div>{addresses.length ? <div className="address-list">{addresses.map((item) => <article className="address-card" key={item.id}><header><strong>{item.recipient_name || '未填写收件人'}</strong>{item.is_default && <Tag color="app-teal">默认地址</Tag>}</header><p>{item.address_text}</p><small>{[item.phone, item.email, item.city, item.region, item.postal_code, item.country].filter(Boolean).join(' · ')}</small><div className="row-actions"><button className="table-action" onClick={() => void navigator.clipboard.writeText(formatAddress(item))}>复制</button>{canEdit && <><button className="table-action" onClick={() => setAddress(item)}>编辑</button>{!item.is_default && <button className="table-action" onClick={() => void makeDefault(item)}>设为默认</button>}<button className="table-action danger-text" onClick={() => void removeAddress(item)}>删除</button></>}</div></article>)}</div> : <p className="muted">尚未登记收件地址</p>}<div className="section-heading"><h3>合作摘要</h3></div><div className="record-summary"><span>合作执行单 {data.campaigns?.length || 0} 条 · 内容产出 {data.deliverables?.length || 0} 条</span></div></div>{contact && <ContactDrawer value={contact} onClose={() => setContact(null)} onSaved={() => { setContact(null); void load(); onChanged(); }} />}{address && <AddressDrawer value={address} contacts={contacts} onClose={() => setAddress(null)} onSaved={() => { setAddress(null); void load(); }} />}</Dialog>;
}

function formatAddress(item: Partial<ShippingAddress>) { return [item.recipient_name, item.phone, item.email, item.address_text, [item.city, item.region, item.postal_code, item.country].filter(Boolean).join(' '), item.tax_or_customs_number ? `税号/清关号: ${item.tax_or_customs_number}` : '', item.shipping_notes].filter(Boolean).join('\n'); }

function AddressDrawer({ value, contacts, onClose, onSaved }: { value: any; contacts: any[]; onClose: () => void; onSaved: () => void }) { const [form, setForm] = useState(value); const set = (key: string, next: any) => setForm({ ...form, [key]: next }); const save = async () => { if (!form.address_text?.trim()) return Notification.error({ message: '请填写完整地址' }); await api(form.id ? `/api/shipping-addresses/${form.id}` : '/api/shipping-addresses', { method: form.id ? 'PUT' : 'POST', body: JSON.stringify({ ...form, address_text: form.address_text.trim() }) }); onSaved(); }; return <Dialog title={form.id ? '编辑收件地址' : '新增收件地址'} onClose={onClose} onOk={() => void save()}><div className="form-grid"><label>关联联系人<SelectField value={form.contact_id || ''} onChange={(x) => set('contact_id', x ? Number(x) : null)} options={contacts.map((item) => ({ key: String(item.id), label: item.name || `联系人 ${item.id}` }))} placeholder="不指定联系人" /></label><label>收件人<Input value={form.recipient_name || ''} onChange={(e) => set('recipient_name', e.target.value)} /></label><label>电话<Input value={form.phone || ''} onChange={(e) => set('phone', e.target.value)} /></label><label>邮箱<Input value={form.email || ''} onChange={(e) => set('email', e.target.value)} /></label><label className="wide">完整地址<textarea value={form.address_text || ''} onChange={(e) => set('address_text', e.target.value)} /></label><label>城市<Input value={form.city || ''} onChange={(e) => set('city', e.target.value)} /></label><label>省 / 州<Input value={form.region || ''} onChange={(e) => set('region', e.target.value)} /></label><label>邮编<Input value={form.postal_code || ''} onChange={(e) => set('postal_code', e.target.value)} /></label><label>国家<Input value={form.country || ''} onChange={(e) => set('country', e.target.value)} /></label><label className="wide">税号 / 清关号<Input value={form.tax_or_customs_number || ''} onChange={(e) => set('tax_or_customs_number', e.target.value)} /></label><label className="wide">寄送说明<textarea value={form.shipping_notes || ''} onChange={(e) => set('shipping_notes', e.target.value)} /></label><label className="wide">原始文本<textarea value={form.source_text || ''} onChange={(e) => set('source_text', e.target.value)} /></label><label className="checkbox-label"><input type="checkbox" checked={Boolean(form.is_default)} onChange={(e) => set('is_default', e.target.checked)} />设为该媒体默认地址</label></div></Dialog>; }

function AddressImportReview({ onClose }: { onClose: () => void }) { const [items, setItems] = useState<any[]>([]); const [sourceAvailable, setSourceAvailable] = useState(true); const [editing, setEditing] = useState<any>(null); useEffect(() => { api<any>('/api/address-import/candidates').then((result) => { setItems(result.items || []); setSourceAvailable(result.source_available); }); }, []); const pending = items.filter((item) => !item.imported); return <Dialog title="历史地址导入审核" onClose={onClose}><div className="review-note">候选不会自动写入地址库。请逐条确认媒体、联系人和地址字段。</div>{!sourceAvailable ? <p className="muted">本机未找到历史清洗文件，可直接在媒体详情中新增地址。</p> : pending.length ? <div className="review-list">{pending.map((item) => <div className="review-row" key={item.id}><div><strong>{item.media_name || '未匹配媒体'}</strong><span>{item.contact_name || '未匹配联系人'}</span><p>{item.raw_text}</p></div><Button disabled={!item.media_id} onClick={() => setEditing({ ...item.parsed, media_id: item.media_id, contact_id: item.contact_id, is_default: false })}>{item.media_id ? '审核导入' : '请先匹配媒体'}</Button></div>)}</div> : <p className="muted">没有待审核的地址候选</p>}{editing && <AddressDrawer value={editing} contacts={[]} onClose={() => setEditing(null)} onSaved={() => { setEditing(null); api<any>('/api/address-import/candidates').then((result) => setItems(result.items || [])); }} />}</Dialog>; }

function ContactManager({ canEdit }: { canEdit: boolean }) { const [items, setItems] = useState<any[]>([]); const [q, setQ] = useState(''); const [editing, setEditing] = useState<any>(null); const load = () => api<{ items: any[] }>(`/api/contacts?q=${encodeURIComponent(q)}&page_size=300`).then((x) => setItems(x.items)); useEffect(() => { void load(); }, []); return <section><PageHeader title="联系人" action={<div className="page-actions">{canEdit && <Button type="primary" icon={<Plus size={16} />} onClick={() => setEditing({ name: '', role: '', email: '', phone: '', media_id: null, media_label: '' })}>新建联系人</Button>}<Button icon={<RefreshCw size={16} />} onClick={load}>刷新</Button></div>} /><div className="filters"><Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="搜索姓名、邮箱或媒体" /><Button onClick={load}>查询</Button></div><DataTable data={items} columns={[{ title: '媒体', render: (_: any, r: any) => r.media?.name || '-', width: 180 }, { title: '姓名', render: (_: any, r: any) => canEdit ? <button className="link-button" onClick={() => setEditing({ ...r, media_label: r.media ? `${r.media.name}${r.media.country ? ` · ${r.media.country}` : ''}` : '' })}>{r.name || '未命名'}</button> : (r.name || '未命名'), width: 160 }, { title: '职位', dataIndex: 'role', width: 150 }, { title: '邮箱', dataIndex: 'email', width: 240 }, { title: '电话', dataIndex: 'phone', width: 170 }]} />{editing && <ContactDrawer value={editing} onClose={() => setEditing(null)} onSaved={() => { setEditing(null); void load(); }} />}</section>; }

function MediaForm({ value, setValue }: { value: any; setValue: (value: any) => void }) { const set = (key: string, next: any) => setValue({ ...value, [key]: next }); return <div className="form-grid"><label>名称<Input value={value.name || ''} onChange={(e) => set('name', e.target.value)} /></label><label>国家<Input value={value.country || ''} onChange={(e) => set('country', e.target.value)} /></label><label>渠道<Input value={value.platform_type || ''} onChange={(e) => set('platform_type', e.target.value)} /></label><label>分类<Input value={value.category || ''} onChange={(e) => set('category', e.target.value)} /></label><label className="wide">主页链接<Input value={value.website_url || ''} onChange={(e) => set('website_url', e.target.value)} /></label><label>流量 / 粉丝<Input value={value.followers_or_traffic || ''} onChange={(e) => set('followers_or_traffic', e.target.value ? Number(e.target.value) : null)} /></label><label>媒体等级<Input value={value.media_tier || ''} onChange={(e) => set('media_tier', e.target.value)} /></label><label className="wide">备注<textarea value={value.notes || ''} onChange={(e) => set('notes', e.target.value)} /></label></div>; }

function ContactDrawer({ value, onClose, onSaved }: { value: any; onClose: () => void; onSaved: () => void }) { const [form, setForm] = useState(value); const [media, setMedia] = useState<Media[]>([]); const [quickMedia, setQuickMedia] = useState<any>(null); useEffect(() => { api<{ items: Media[] }>('/api/media?page_size=500').then((x) => setMedia(x.items)); }, []); const save = async () => { if (!form.media_id) return Notification.error({ message: '请先选择或新建挂靠媒体' }); await api(form.id ? `/api/contacts/${form.id}` : '/api/contacts', { method: form.id ? 'PUT' : 'POST', body: JSON.stringify({ ...form, media_id: form.media_id }) }); onSaved(); }; const saveQuickMedia = async () => { const created = await api<any>('/api/media', { method: 'POST', body: JSON.stringify(quickMedia) }); setMedia([...media, created]); setForm({ ...form, media_id: created.id }); setQuickMedia(null); }; return <><Dialog title={form.id ? '编辑联系人' : '新建联系人'} onClose={onClose} onOk={() => void save()}><div className="form-grid"><label className="wide">挂靠媒体 / KOL<EntityLookup value={form.media_id} onChange={(mediaId) => setForm({ ...form, media_id: mediaId })} options={mediaLookupOptions(media)} placeholder="输入媒体名称、国家、渠道或主页链接" /><button type="button" className="link-button" onClick={() => setQuickMedia({ name: '', country: '', platform_type: '', website_url: '' })}>没有对应媒体？新建媒体</button></label><label>姓名<Input value={form.name || ''} onChange={(e) => setForm({ ...form, name: e.target.value })} /></label><label>职位<Input value={form.role || ''} onChange={(e) => setForm({ ...form, role: e.target.value })} /></label><label>Email<Input value={form.email || ''} onChange={(e) => setForm({ ...form, email: e.target.value })} /></label><label>电话<Input value={form.phone || ''} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></label><label>WhatsApp<Input value={form.whatsapp || ''} onChange={(e) => setForm({ ...form, whatsapp: e.target.value })} /></label><label>Telegram<Input value={form.telegram || ''} onChange={(e) => setForm({ ...form, telegram: e.target.value })} /></label><label>Brief 邮箱<Input value={form.brief_email || ''} onChange={(e) => setForm({ ...form, brief_email: e.target.value })} /></label><label>PR 邮箱<Input value={form.press_release_email || ''} onChange={(e) => setForm({ ...form, press_release_email: e.target.value })} /></label><label className="wide">备注<textarea value={form.notes || ''} onChange={(e) => setForm({ ...form, notes: e.target.value })} /></label></div></Dialog>{quickMedia && <Dialog title="新建挂靠媒体" onClose={() => setQuickMedia(null)} onOk={() => void saveQuickMedia()}><MediaForm value={quickMedia} setValue={setQuickMedia} /></Dialog>}</>; }

function ProductManager({ canEdit, canManage }: { canEdit: boolean; canManage: boolean }) {
  const [items, setItems] = useState<any[]>([]); const [allProducts, setAllProducts] = useState<any[]>([]); const [q, setQ] = useState(''); const [projects, setProjects] = useState<Project[]>([]); const [editing, setEditing] = useState<any>(null); const [merging, setMerging] = useState<any>(null); const [targetProductId, setTargetProductId] = useState<number | null>(null);
  const load = () => api<{ items: any[] }>(`/api/products?q=${encodeURIComponent(q)}&page_size=300`).then((x) => setItems(x.items)); useEffect(() => { void load(); api<{ items: any[] }>('/api/products?page_size=500').then((x) => setAllProducts(x.items)); api<{ items: Project[] }>('/api/projects?page_size=300').then((x) => setProjects(x.items)); }, []);
  const refreshProducts = async () => { await load(); const result = await api<{ items: any[] }>('/api/products?page_size=500'); setAllProducts(result.items); };
  const save = async () => { try { await api(editing.id ? `/api/products/${editing.id}` : '/api/products', { method: editing.id ? 'PUT' : 'POST', body: JSON.stringify(editing) }); setEditing(null); await refreshProducts(); Notification.success({ message: '产品已保存' }); } catch (error) { Notification.error({ message: '保存失败', description: String(error) }); } };
  const remove = async (product: any) => { if (!window.confirm(`确定删除产品“${product.model}”吗？\n\n若它仍关联历史寄样或执行单，系统会阻止删除，请先使用“合并”。`)) return; try { await api(`/api/products/${product.id}`, { method: 'DELETE' }); await refreshProducts(); Notification.success({ message: '产品已删除' }); } catch (error) { Notification.error({ message: '删除失败', description: String(error) }); } };
  const merge = async () => { if (!merging || !targetProductId) return Notification.error({ message: '请选择合并目标产品' }); const target = allProducts.find((item) => item.id === targetProductId); if (!target || !window.confirm(`将“${merging.model}”合并到“${target.model}”？\n\n源产品的历史寄样、执行单和项目关联会转移到目标产品，源产品随后删除。此操作不可撤销。`)) return; try { const result = await api<any>(`/api/products/${merging.id}/merge`, { method: 'POST', body: JSON.stringify({ target_product_id: targetProductId }) }); setMerging(null); setTargetProductId(null); await refreshProducts(); Notification.success({ message: `已合并：转移 ${result.shipment_count} 条寄样、${result.campaign_count} 条执行单` }); } catch (error) { Notification.error({ message: '合并失败', description: String(error) }); } };
  return <section><PageHeader title="产品库" action={<div className="page-actions">{canEdit && <Button type="primary" icon={<Plus size={16} />} onClick={() => setEditing({ model: '', full_name: '', product_line: '', platform: '', aliases: '', notes: '', project_ids: [] })}>新建产品</Button>}<Button icon={<RefreshCw size={16} />} onClick={() => void refreshProducts()}>刷新</Button></div>} /><div className="filters"><Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="搜索完整型号、全名或别名" /><Button onClick={() => void load()}>查询</Button></div><DataTable data={items} columns={[{ title: '完整型号', render: (_: any, r: any) => <button className="link-button" onClick={() => canEdit && setEditing({ ...r })}>{r.model}</button>, width: 260 }, { title: '芯片组', dataIndex: 'platform', width: 110 }, { title: '产品线', dataIndex: 'product_line', width: 140 }, { title: '挂靠项目', render: (_: any, r: any) => (r.projects || []).map((x: any) => x.name).join('、') || '未关联', width: 230 }, { title: '历史寄样', dataIndex: 'shipment_count', width: 100 }, ...(canEdit ? [{ title: '管理', render: (_: any, r: any) => <div className="row-actions"><button className="table-action" onClick={() => setEditing({ ...r })}><Pencil size={15} />编辑</button>{canManage && <><button className="table-action" onClick={() => { setMerging(r); setTargetProductId(null); }}>合并</button><button className="danger-button" onClick={() => void remove(r)}><Trash2 size={15} />删除</button></>}</div>, width: canManage ? 220 : 100 }] : [])]} />{editing && <Dialog title={editing.id ? '编辑产品' : '新建产品'} onClose={() => setEditing(null)} onOk={() => void save()}><ProductForm value={editing} projects={projects} setValue={setEditing} /></Dialog>}{merging && <Dialog title={`合并产品 · ${merging.model}`} onClose={() => { setMerging(null); setTargetProductId(null); }} onOk={() => void merge()}><div className="form-grid"><label className="wide">合并到<EntityLookup value={targetProductId} onChange={setTargetProductId} options={allProducts.filter((item) => item.id !== merging.id).map((item) => ({ id: item.id, label: item.model, search: `${item.model} ${item.full_name || ''} ${item.aliases || ''} ${item.platform || ''}` }))} placeholder="输入完整型号、别名或芯片组" /></label><p className="wide merge-warning">源产品的寄样、执行单和项目关联会转移到目标产品；源产品会删除，无法在页面内撤销。</p></div></Dialog>}</section>;
}

function ProductForm({ value, projects, setValue }: { value: any; projects: Project[]; setValue: (value: any) => void }) { const set = (key: string, next: any) => setValue({ ...value, [key]: next }); const toggle = (id: number) => set('project_ids', value.project_ids?.includes(id) ? value.project_ids.filter((x: number) => x !== id) : [...(value.project_ids || []), id]); return <div className="form-grid"><label>完整型号<Input value={value.model || ''} onChange={(e) => set('model', e.target.value)} /></label><label>芯片组 / 平台<Input value={value.platform || ''} onChange={(e) => set('platform', e.target.value)} /></label><label>全名<Input value={value.full_name || ''} onChange={(e) => set('full_name', e.target.value)} /></label><label>产品线<Input value={value.product_line || ''} onChange={(e) => set('product_line', e.target.value)} /></label><label className="wide">别名<Input value={value.aliases || ''} onChange={(e) => set('aliases', e.target.value)} /></label><label className="wide">挂靠推广项目<div className="project-checks">{projects.map((x) => <label key={x.id}><input type="checkbox" checked={value.project_ids?.includes(x.id) || false} onChange={() => toggle(x.id)} />{x.name}</label>)}</div></label><label className="wide">备注<textarea value={value.notes || ''} onChange={(e) => set('notes', e.target.value)} /></label></div>; }

function UsersPage() { const [items, setItems] = useState<User[]>([]); const [form, setForm] = useState<any>(null); const load = () => api<{ items: User[] }>('/api/users').then((x) => setItems(x.items)); useEffect(() => { void load(); }, []); const save = async () => { if (!form?.name || !form?.email || !form?.password) return Notification.error({ message: '请填写姓名、邮箱和密码' }); if (form.password.length < 8) return Notification.error({ message: '密码至少 8 位' }); try { await api('/api/users', { method: 'POST', body: JSON.stringify(form) }); setForm(null); await load(); Notification.success({ message: '账号已创建' }); } catch (error) { Notification.error({ message: '创建失败', description: String(error) }); } }; return <section><PageHeader title="用户管理" action={<div className="page-actions"><Button type="primary" icon={<Plus size={16} />} onClick={() => setForm({ name: '', email: '', password: '', role: 'Editor' })}>新建用户</Button><Button icon={<RefreshCw size={16} />} onClick={load}>刷新</Button></div>} /><DataTable data={items} columns={[{ title: '姓名', dataIndex: 'name' }, { title: '邮箱', dataIndex: 'email' }, { title: '角色', dataIndex: 'role' }]} />{form && <Dialog title="新建 CRM 账号" onClose={() => setForm(null)} onOk={() => void save()}><div className="form-grid"><label>姓名<Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></label><label>角色<SelectField value={form.role} onChange={(role) => setForm({ ...form, role })} options={[{ key: 'Editor', label: 'Editor（可新增和编辑）' }, { key: 'Viewer', label: 'Viewer（仅查看）' }, { key: 'Admin', label: 'Admin（管理权限）' }]} /></label><label className="wide">邮箱<Input type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} placeholder="test@example.com" /></label><label className="wide">初始密码<Input type="password" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} placeholder="至少 8 位" /></label></div></Dialog>}</section>; }

function ExecutionImport() { const [file, setFile] = useState<File | null>(null); const [preview, setPreview] = useState<any>(null); const send = async (mode: 'preview' | 'confirm') => { if (!file) return Notification.error({ message: '请选择费用统计表' }); const body = new FormData(); body.append('file', file); try { const result = await api<any>(`/api/execution-import/${mode}`, { method: 'POST', body }); setPreview(result); if (mode === 'confirm') Notification.success({ message: `已导入 ${result.success_count} 条执行记录` }); } catch (e) { Notification.error({ message: '导入失败', description: String(e) }); } }; return <section><PageHeader title="费用统计表导入" /><Card><div className="import-box"><input type="file" accept=".xlsx" onChange={(e) => setFile(e.target.files?.[0] || null)} /><Button onClick={() => send('preview')}>审核预览</Button><Button type="primary" onClick={() => send('confirm')}>确认导入</Button></div><p className="import-note">原始文件不会被修改。含 OA/PI 的记录按编号归入项目；缺少 OA/PI 的记录会进入“历史导入待归类”。</p></Card>{preview?.rows && <><div className="import-summary"><strong>{preview.total} 条记录</strong><span>{preview.warning_count} 个需要注意的字段</span></div><DataTable data={preview.rows} columns={[{ title: '行', dataIndex: 'row_number', width: 70 }, { title: '项目编号', dataIndex: 'project_code', width: 160 }, { title: '合作对象', dataIndex: 'media_name', width: 180 }, { title: '执行状态', render: (_: any, r: any) => <StatusTag value={r.execution_status} />, width: 140 }, { title: '产品', dataIndex: 'product_bundle', width: 250 }, { title: '物流单号', dataIndex: 'tracking_number', width: 160 }, { title: '需确认', render: (_: any, r: any) => r.warnings?.join('；') || '无', width: 270 }]} /></>}</section>; }

createRoot(document.getElementById('root')!).render(<App />);
